func runStatus(cmd *cobra.Command, args []string) error {
    sessionName := getSessionName(args)
    jsonOutput, _ := cmd.Flags().GetBool("json")

    // Get session info
    manager := robot.NewManager(projectDir)
    session, err := manager.GetSession(sessionName)
    if err != nil {
        return fmt.Errorf("session not found: %w", err)
    }

    // Get handoff info
    reader := handoff.NewReader(projectDir)
    goal, now, _ := reader.ExtractGoalNow(sessionName)
    h, path, _ := reader.FindLatest(sessionName)

    // Get context usage
    monitor := context.NewMonitor(projectDir)
    usage := monitor.GetAllUsage()

    if jsonOutput {
        return outputRobotStatus(session, h, path, usage)
    }

    // Human output
    fmt.Printf("Session: %s\n", sessionName)
    fmt.Printf("Status: %s\n", session.Status)
    fmt.Printf("Agents: %d (%s)\n\n", len(session.Panes), summarizeAgents(session.Panes))

    if h != nil {
        age := time.Since(h.CreatedAt)
        fmt.Printf("Latest Handoff (%s):\n", humanizeDuration(age))
        fmt.Printf("  Goal: %s\n", goal)
        fmt.Printf("  Now: %s\n\n", now)
    }

    if len(usage) > 0 {
        fmt.Println("Context Usage:")
        for paneID, pct := range usage {
            bar := renderProgressBar(pct, 20)
            warning := ""
            if pct >= 85 {
                warning = " 🔴"
            } else if pct >= 70 {
                warning = " 🟠"
            }
            fmt.Printf("  %s: %.0f%% %s%s\n", paneID, pct, bar, warning)
        }
    }

    return nil
}

func renderProgressBar(pct float64, width int) string {
    filled := int(pct / 100 * float64(width))
    empty := width - filled
    return "[" + strings.Repeat("█", filled) + strings.Repeat("░", empty) + "]"
}
